import{_ as e}from"./chunks/ue-quick-menu.CKRco9JD.js";import{_ as o,o as n,c as r,ag as a}from"./chunks/framework.BqfgOMAh.js";const b=JSON.parse('{"title":"UE Quick Menu","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/quick-menu.md","filePath":"en/guide/quick-menu.md"}'),i={name:"en/guide/quick-menu.md"};function d(l,t,s,h,c,u){return n(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="ue-quick-menu" tabindex="-1">UE Quick Menu <a class="header-anchor" href="#ue-quick-menu" aria-label="Permalink to &quot;UE Quick Menu&quot;">​</a></h1><p>The Quick Menu lets you invoke AI operations directly within the Unreal Engine Editor — no need to switch to the NexusFlow sidebar to type a request.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>NexusFlow provides <strong>four entry points</strong> in the UE Editor, offering a total of <strong>17 AI operations</strong>:</p><table tabindex="0"><thead><tr><th>Entry Point</th><th>Location</th><th>Operations</th></tr></thead><tbody><tr><td><a href="#blueprint-editor-right-click-menu">Blueprint Editor Right-Click</a></td><td>Right-click in the Blueprint graph</td><td>13 operations</td></tr><tr><td><a href="#content-browser-right-click-menu">Content Browser Right-Click</a></td><td>Right-click on Blueprint assets</td><td>2 operations</td></tr><tr><td><a href="#blueprint-editor-toolbar">Blueprint Editor Toolbar</a></td><td>Toolbar inside the Blueprint Editor</td><td>2 operations</td></tr><tr><td><a href="#level-editor-toolbar">Level Editor Toolbar</a></td><td>Main editor toolbar (NexusFlow button)</td><td>Connection status + quick access</td></tr></tbody></table><p>When you select an operation, NexusFlow automatically:</p><ol><li>Opens the sidebar (if hidden) and focuses the chat input</li><li>Sends the preset prompt with full Blueprint context</li><li>Displays the AI response in the sidebar</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If the AI is currently processing a request, the Quick Menu will show a toast notification and discard the new prompt to avoid conflicts.</p></div><h2 id="blueprint-editor-right-click-menu" tabindex="-1">Blueprint Editor Right-Click Menu <a class="header-anchor" href="#blueprint-editor-right-click-menu" aria-label="Permalink to &quot;Blueprint Editor Right-Click Menu&quot;">​</a></h2><p><img src="'+e+'" alt="Blueprint Editor right-click showing NexusFlow AI submenu"></p><p>Open a Blueprint, optionally select one or more nodes, then <strong>right-click</strong> in the graph area. The NexusFlow submenu appears with operations filtered by your selection.</p><h3 id="selection-mode" tabindex="-1">Selection Mode <a class="header-anchor" href="#selection-mode" aria-label="Permalink to &quot;Selection Mode&quot;">​</a></h3><p>Each operation has a <strong>selection mode</strong> that controls when it appears in the menu:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Meaning</th><th>Example</th></tr></thead><tbody><tr><td><code>any</code></td><td>Always visible, regardless of selection</td><td>Explain Graph, Organize Layout</td></tr><tr><td><code>single</code></td><td>Visible only when <strong>exactly 1 node</strong> is selected</td><td>Explain Selected Nodes</td></tr><tr><td><code>multi</code></td><td>Visible only when <strong>2 or more nodes</strong> are selected</td><td>Extract to Function</td></tr></tbody></table><h3 id="available-operations-13" tabindex="-1">Available Operations (13) <a class="header-anchor" href="#available-operations-13" aria-label="Permalink to &quot;Available Operations (13)&quot;">​</a></h3><h4 id="explain-analyze" tabindex="-1">Explain &amp; Analyze <a class="header-anchor" href="#explain-analyze" aria-label="Permalink to &quot;Explain &amp; Analyze&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Operation</th><th>Selection</th><th>Description</th></tr></thead><tbody><tr><td><strong>Explain Graph</strong></td><td>any</td><td>Analyze the entire graph&#39;s logic and data flow</td></tr><tr><td><strong>Explain Selected Nodes</strong></td><td>single</td><td>Deep-dive into what the selected node does</td></tr></tbody></table><h4 id="optimize-refactor" tabindex="-1">Optimize &amp; Refactor <a class="header-anchor" href="#optimize-refactor" aria-label="Permalink to &quot;Optimize &amp; Refactor&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Operation</th><th>Selection</th><th>Description</th></tr></thead><tbody><tr><td><strong>Optimize Selected Nodes</strong></td><td>single</td><td>Suggest performance or readability improvements</td></tr><tr><td><strong>Extract to Function</strong></td><td>multi</td><td>Extract selected nodes into a reusable function</td></tr><tr><td><strong>Extract to Macro</strong></td><td>multi</td><td>Extract selected nodes into a macro</td></tr><tr><td><strong>Organize Layout</strong></td><td>any</td><td>Reorganize node positions for better readability</td></tr><tr><td><strong>Simplify Connections</strong></td><td>any</td><td>Reduce unnecessary wires and reroute nodes</td></tr></tbody></table><h4 id="document" tabindex="-1">Document <a class="header-anchor" href="#document" aria-label="Permalink to &quot;Document&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Operation</th><th>Selection</th><th>Description</th></tr></thead><tbody><tr><td><strong>Document Graph</strong></td><td>any</td><td>Generate documentation for the entire graph</td></tr><tr><td><strong>Document Function</strong></td><td>any</td><td>Generate parameter and return value documentation</td></tr></tbody></table><h4 id="clean-up-fix" tabindex="-1">Clean Up &amp; Fix <a class="header-anchor" href="#clean-up-fix" aria-label="Permalink to &quot;Clean Up &amp; Fix&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Operation</th><th>Selection</th><th>Description</th></tr></thead><tbody><tr><td><strong>Clean Up Unused Variables</strong></td><td>any</td><td>Identify and remove unused variables</td></tr><tr><td><strong>Fix Compile Errors</strong></td><td>any</td><td>Analyze and suggest fixes for compile errors</td></tr><tr><td><strong>Fix Broken References</strong></td><td>any</td><td>Find and resolve broken asset/node references</td></tr><tr><td><strong>Fix Deprecated Nodes</strong></td><td>any</td><td>Identify deprecated nodes and suggest replacements</td></tr></tbody></table><h2 id="content-browser-right-click-menu" tabindex="-1">Content Browser Right-Click Menu <a class="header-anchor" href="#content-browser-right-click-menu" aria-label="Permalink to &quot;Content Browser Right-Click Menu&quot;">​</a></h2><p>In the <strong>Content Browser</strong>, right-click on one or more Blueprint assets to access NexusFlow operations at the asset level.</p><table tabindex="0"><thead><tr><th>Operation</th><th>Selection</th><th>Description</th></tr></thead><tbody><tr><td><strong>Explain Blueprint</strong></td><td>any</td><td>Analyze the overall structure and purpose of a Blueprint</td></tr><tr><td><strong>Document Blueprint</strong></td><td>any</td><td>Generate comprehensive documentation for a Blueprint</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>These operations work on the entire Blueprint asset, not individual nodes. They&#39;re ideal for getting a high-level understanding of Blueprints you didn&#39;t write.</p></div><h2 id="blueprint-editor-toolbar" tabindex="-1">Blueprint Editor Toolbar <a class="header-anchor" href="#blueprint-editor-toolbar" aria-label="Permalink to &quot;Blueprint Editor Toolbar&quot;">​</a></h2><p>When a Blueprint is open in the editor, two buttons appear in the <strong>Blueprint Editor toolbar</strong> (top bar):</p><table tabindex="0"><thead><tr><th>Operation</th><th>Description</th></tr></thead><tbody><tr><td><strong>Review Blueprint</strong></td><td>Perform a quality review of the current Blueprint (structure, naming, best practices)</td></tr><tr><td><strong>Summarize Blueprint</strong></td><td>Generate a concise summary of what the Blueprint does</td></tr></tbody></table><p>These toolbar buttons are always visible — they don&#39;t depend on node selection.</p><h2 id="level-editor-toolbar" tabindex="-1">Level Editor Toolbar <a class="header-anchor" href="#level-editor-toolbar" aria-label="Permalink to &quot;Level Editor Toolbar&quot;">​</a></h2><p>The NexusFlow button in the <strong>Level Editor main toolbar</strong> provides quick access and connection status at a glance.</p><h3 id="connection-status" tabindex="-1">Connection Status <a class="header-anchor" href="#connection-status" aria-label="Permalink to &quot;Connection Status&quot;">​</a></h3><p>The button icon changes based on whether the NexusFlow desktop app is running:</p><table tabindex="0"><thead><tr><th>Status</th><th>Icon</th><th>Click Behavior</th></tr></thead><tbody><tr><td><strong>Connected</strong></td><td>Color icon</td><td>Opens the sidebar and focuses chat input</td></tr><tr><td><strong>Not Connected</strong></td><td>Gray icon</td><td>Shows a notification with download links</td></tr></tbody></table><h3 id="not-connected-notification" tabindex="-1">Not-Connected Notification <a class="header-anchor" href="#not-connected-notification" aria-label="Permalink to &quot;Not-Connected Notification&quot;">​</a></h3><p>When NexusFlow is not running, clicking the toolbar button displays a notification popup with:</p><ul><li>A message explaining that the NexusFlow desktop app is required</li><li><strong>GitHub</strong> download link — latest release page</li><li><strong>Mirror</strong> download link — accelerated download for users in China</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The Level Editor toolbar button is a quick-access shortcut, not an AI operation trigger. To use AI operations, go through the Blueprint Editor right-click menu, Content Browser right-click menu, or Blueprint Editor toolbar.</p></div><h2 id="language-support" tabindex="-1">Language Support <a class="header-anchor" href="#language-support" aria-label="Permalink to &quot;Language Support&quot;">​</a></h2><p>Quick Menu item names are displayed in the <strong>UE Editor&#39;s language setting</strong>:</p><table tabindex="0"><thead><tr><th>Language</th><th>Example</th></tr></thead><tbody><tr><td>English</td><td>Explain Graph</td></tr><tr><td>简体中文</td><td>解释图表</td></tr><tr><td>繁體中文</td><td>解釋圖表</td></tr></tbody></table><p>The language is determined by UE&#39;s locale, not the NexusFlow app&#39;s language setting.</p><h2 id="context-information" tabindex="-1">Context Information <a class="header-anchor" href="#context-information" aria-label="Permalink to &quot;Context Information&quot;">​</a></h2><p>When a Quick Menu operation is triggered, the following context is automatically collected and sent to the AI:</p><ul><li><strong>Blueprint Asset Path</strong> — The location of the current Blueprint in the project</li><li><strong>Graph Name</strong> — The graph currently being edited (e.g., EventGraph, a function graph)</li><li><strong>Selected Node IDs</strong> — All currently selected Blueprint nodes (if any)</li><li><strong>Extension Point</strong> — Which menu triggered the operation</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The Quick Menu requires the NexusFlow desktop app to be running and connected to UE. If the connection is lost, menu items will still appear but operations won&#39;t be sent.</p></div>',48)])])}const m=o(i,[["render",d]]);export{b as __pageData,m as default};
